import{_ as e,o as r,c as l,a2 as t}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"美股卖空","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"stock-trading/trading-hours-and-rules/us-short-selling.md","filePath":"zh-CN/stock-trading/trading-hours-and-rules/us-short-selling.md"}'),i={name:"stock-trading/trading-hours-and-rules/us-short-selling.md"};function o(h,a,n,s,d,u){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="美股卖空" tabindex="-1">美股卖空 <a class="header-anchor" href="#美股卖空" aria-label="Permalink to &quot;美股卖空&quot;">​</a></h1><p>美股融券卖空条件、操作流程、融券利息计算、强平规则及派息处理。</p><h2 id="什么是美股卖空" tabindex="-1">什么是美股卖空 <a class="header-anchor" href="#什么是美股卖空" aria-label="Permalink to &quot;什么是美股卖空&quot;">​</a></h2><p>融券是美股最基本的卖空方式，与做多操作相反。当投资者认为某股票未来价格会下跌且尚未持有该股票时，可将证券账户内的资金（保证金）作为抵押物向长桥借入该股票并卖出。</p><p>待股价下跌时低价买进同等数量股票归还，从中赚取高卖低买的差价。</p><h2 id="卖空条件" tabindex="-1">卖空条件 <a class="header-anchor" href="#卖空条件" aria-label="Permalink to &quot;卖空条件&quot;">​</a></h2><ul><li>已开通长桥证券综合账户（保证金账户），现金账户不支持</li><li>账户内有足够购买力（账户资产 &gt; 融券个股所需初始保证金）</li><li>该股票支持长桥卖空</li></ul><p>每个支持卖空的股票融券保证金率不同，具体可在个股详情页查看。入金或存入可抵押股票均可提升购买力。</p><h2 id="如何查看是否支持卖空" tabindex="-1">如何查看是否支持卖空 <a class="header-anchor" href="#如何查看是否支持卖空" aria-label="Permalink to &quot;如何查看是否支持卖空&quot;">​</a></h2><p>进入个股详情页，查看右上角补充信息，如包含「支持卖空融券」则可融券卖出。点击可查看卖空所需保证金、券息、融券池额度等信息。</p><p>支持卖空股票名单会根据公司政策及市场风险不时调整。并非所有美股都能卖空，价格非常低或流动性非常差的股票不允许卖空。</p><h2 id="卖空操作" tabindex="-1">卖空操作 <a class="header-anchor" href="#卖空操作" aria-label="Permalink to &quot;卖空操作&quot;">​</a></h2><p>下单界面选择卖出方向，输入数量下方会显示「可卖空」额度，根据额度输入数量后提交订单。</p><h3 id="空头转多头" tabindex="-1">空头转多头 <a class="header-anchor" href="#空头转多头" aria-label="Permalink to &quot;空头转多头&quot;">​</a></h3><p>需先平仓（买入空仓股数）后再下新买入单。例如卖空 200 股，需先买入 200 股平仓，再下新买入单。直接买入 400 股会下单失败。</p><h3 id="同一股票限制" tabindex="-1">同一股票限制 <a class="header-anchor" href="#同一股票限制" aria-label="Permalink to &quot;同一股票限制&quot;">​</a></h3><p>同一证券账户无法同时做多和卖空一支股票。持有多头时卖出相同数量视为平仓，超过持仓数量则下单失败。</p><h2 id="收费" tabindex="-1">收费 <a class="header-anchor" href="#收费" aria-label="Permalink to &quot;收费&quot;">​</a></h2><h3 id="交易费用" tabindex="-1">交易费用 <a class="header-anchor" href="#交易费用" aria-label="Permalink to &quot;交易费用&quot;">​</a></h3><p>与做多方向交易费率相同（佣金、平台费、第三方收费）。</p><h3 id="融券利息" tabindex="-1">融券利息 <a class="header-anchor" href="#融券利息" aria-label="Permalink to &quot;融券利息&quot;">​</a></h3><p>借入股票卖出且未在日内买回平仓，需支付融券利息。</p><p>融券利息 = 每日已交收卖空股票数量 ×【（收盘价 × 102%）向上取整】× 卖空参考利率 ÷ 360</p><ul><li>融券利息每日计提，月底合计扣费</li><li>卖空参考利率和收盘价可能浮动，最终以每日清算后的利率计算</li><li>每支股票不同时间点卖空参考利率可能不同，具体在个股详情页查询</li></ul><h3 id="计息时间" tabindex="-1">计息时间 <a class="header-anchor" href="#计息时间" aria-label="Permalink to &quot;计息时间&quot;">​</a></h3><p>美股 T+1 交收，计息在股票完成交收后开始。融券期间每日不会实时扣除利息，但计息会每日影响购买力，请确保账户内有足够保证金。</p><h2 id="融券担保品规则" tabindex="-1">融券担保品规则 <a class="header-anchor" href="#融券担保品规则" aria-label="Permalink to &quot;融券担保品规则&quot;">​</a></h2><p>卖空成交后，系统自动计算担保金 = 与借入股份实时市值等值的现金。担保金以保证金方式收取，不计入现金购买力。若现金扣减空头平仓担保额后产生欠款，将按融资欠款计算利息。</p><h2 id="融券与融资额度" tabindex="-1">融券与融资额度 <a class="header-anchor" href="#融券与融资额度" aria-label="Permalink to &quot;融券与融资额度&quot;">​</a></h2><p>若客户没有足够现金进行卖空，实际上是券商借款给客户卖空，会占用融资额度。</p><p>示例：现金为 0，卖空 AAPL 1 股 130 美元，初始保证金需 50 美元 → 券商借出 50 美元，占用融资额度。<br> 示例：现金 100 美元，卖空 AAPL 1 股 130 美元，初始保证金需 50 美元 → 现金足够，不占用融资额度。</p><h2 id="追缴保证金与强平" tabindex="-1">追缴保证金与强平 <a class="header-anchor" href="#追缴保证金与强平" aria-label="Permalink to &quot;追缴保证金与强平&quot;">​</a></h2><p>卖空股票市值上升导致账户资产净值低于维持保证金时，会触发追缴保证金（Margin Call）。资产净值低于强平保证金或追缴限期到时，账户可能随时被强平。</p><h2 id="卖空期间派息" tabindex="-1">卖空期间派息 <a class="header-anchor" href="#卖空期间派息" aria-label="Permalink to &quot;卖空期间派息&quot;">​</a></h2><p>融券期间如发生股票派息，且在除权日前一个交易日仍持有空头头寸，长桥将在股息支付日从账户扣取分红金额。由于除权后股价下跌，空头仓位会增加相同金额浮盈，一减一增刚好抵消。如不想支付分红，可于除权日前一个交易日之前平仓。</p><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ul><li><strong>风险与收益不对等</strong>：做多最大亏损为 100%，卖空潜在亏损没有上限（股价可无限上涨）</li><li><strong>时间成本</strong>：卖空每天产生利息，随时间累积成本增加</li><li><strong>利率风险</strong>：卖空利率随市场变化，个股卖空拥挤度增加可能导致利率大幅上涨</li><li><strong>公司行动</strong>：并购、收购、分红等可能增加卖空成本</li><li><strong>退市和停牌</strong>：股票无法交易期间仍需按最近交易日价格持续支付融券费用</li><li><strong>股票归还</strong>：长桥可酌情要求客户随时归还借入的股票</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/stock-trading/交易时间与规则/美股交易规则与结算">美股交易规则与结算</a> — 美股市场规则</li><li><a href="/margin/融资额度与保证金规则">融资额度与保证金规则</a> — 卖空保证金要求</li></ul>',39)])])}const b=e(i,[["render",o]]);export{p as __pageData,b as default};
